{"content": "import type { MetadataRoute } from "next"

/**
 * robots.ts template for Next.js App Router sites.
 * Replace SITE_URL with the actual site URL before using.
 *
 * Usage:
 * 1. Copy this file to app/robots.ts
 * 2. Replace SITE_URL with the actual domain
 */

const SITE_URL = "https://example.paragu-ai.com"

export default function robots(): MetadataRoute.Robots {
  return {
    rules: [
      {
        userAgent: "*",
        allow: "/",
        disallow: ["/admin", "/api", "/_next/"],
      },
    ],
    sitemap: `${SITE_URL}/sitemap.xml`,
  }
}
", "path": "/root/templates/robots.ts"}
